css_snippet:
body {
  font-family: 'Roboto', 'Arial', sans-serif; /* Primary web font, then fallback system fonts */
  font-size: 1rem;
  /* 'Roboto' has an average x-height to font-size ratio of approximately 0.53.
     By setting font-size-adjust to this value, the browser will scale 'Arial'
     or 'sans-serif' to match Roboto's x-height at 1rem, ensuring visual consistency.
  */
  font-size-adjust: 0.53;
  line-height: 1.6;
}

h1 {
  font-family: 'Playfair Display', 'Georgia', serif; /* Primary display font */
  font-size: 2.5rem;
  /* 'Playfair Display' typically has a lower x-height ratio, around 0.45.
     Setting font-size-adjust to 0.45 ensures that 'Georgia' or other serif fallbacks
     are scaled to maintain a similar visual x-height to 'Playfair Display'.
  */
  font-size-adjust: 0.45;
  line-height: 1.2;
}
